output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic Volume",
      "simple": "Choose the pelvic CT volume from the 'Input CT Volume' dropdown.",
      "detailed": "The pelvic CT scan is the main input for segmentation and planning. Select the correct pelvic volume to ensure all subsequent steps use the right dataset. In the 'Input CT Volume' dropdown, pick the appropriate pelvic volume."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button to begin automatic segmentation of the pelvic bone.",
      "detailed": "This step automatically segments the pelvic bone from the selected CT volume, creating a 3D model. The segmentation is the foundation for identifying fracture fragments and planning reduction. Press the 'Run Step 1: Segment Pelvis' button and wait for the process to complete."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fracture Fragments",
      "simple": "Click the 'Run Step 2: Segment Fractures' button to automatically identify fracture fragments.",
      "detailed": "This step automatically detects and segments individual fracture fragments from the pelvic bone segmentation. Correct fragment identification is critical for subsequent reduction planning. Click the 'Run Step 2: Segment Fractures' button and allow the algorithm to process."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Irrelevant Fragments",
      "simple": "In the fragment list, untick any segments you wish to exclude from planning.",
      "detailed": "Not all fracture fragments may be relevant for the planned reduction or fixation. Review the automatically identified fragments and untick those that are non-displaced or not part of the surgical plan. This refines the working set for template generation and screw planning. In the fragment list, deselect any segments you want to exclude, then click Done."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button to create a template for fracture reduction.",
      "detailed": "This step uses the selected pelvic segments and fracture fragments to generate a template that guides the reduction process. The template represents the anatomical target alignment for the fragments. Press 'Run Step 3: Generate Template' to proceed."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fragments",
      "simple": "Click the 'Run Step 4: Register _Reduce' button to automatically align the fracture fragments to the template.",
      "detailed": "This step performs automated registration of each fracture fragment to the reduction template, achieving a virtual reduction. The result is a reduced pelvic model showing the bone in its intended alignment. Click 'Run Step 4: Register _Reduce' to execute the reduction."
    },
    {
      "step_id": "cb_step_7",
      "title": "Manual Adjustment Decision",
      "simple": "Indicate whether you want to manually adjust a fragment. If yes, select 'Yes'; if not, select 'No' and proceed to screw planning.",
      "detailed": "After automated reduction, you may need to fine-tune the position of individual fragments for optimal alignment. If you are satisfied with the reduction, select 'No' to skip to screw planning. If adjustments are needed, select 'Yes' to enter manual adjustment mode. Choose your option in the dialog."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "From the 'Fragment' dropdown, choose the fragment you want to manually adjust.",
      "detailed": "To correct the alignment of a specific fragment, first identify it in the dropdown. Choose the fragment that requires repositioning or rotation. This step prepares the selected fragment for manual manipulation in the 3D view."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Use the 3D view to manually adjust the position and rotation of the selected fragment.",
      "detailed": "With the fragment selected, you can drag to translate or rotate it in the 3D view to achieve better alignment with the pelvic template. Precise manual adjustment ensures the final reduction matches anatomical norms. Make your adjustments directly in the viewport, then click Done when satisfied."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the 'Apply adjustments' button to finalize the manual changes.",
      "detailed": "After positioning the fragment to your satisfaction, confirm the changes by clicking 'Apply adjustments'. This commits the new position and rotation into the reduction model for use in screw planning."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click the 'Run Step 5: Plan Screws' button to automatically generate screw trajectories.",
      "detailed": "This step analyzes the reduced pelvis and fracture configuration to propose optimal screw trajectories for fixation. The generated screws provide a starting point for insertion planning. Click 'Run Step 5: Plan Screws' to compute the trajectories."
    },
    {
      "step_id": "cb_step_12",
      "title": "Edit Screw Trajectories Decision",
      "simple": "Indicate whether you want to edit the screw trajectories. Select 'Yes' to modify them, or 'No' to finish planning.",
      "detailed": "The automatically planned screws may need adjustment based on patient-specific anatomy or surgical approach. If you are satisfied, select 'No' to complete the planning. If you need to fine-tune the trajectories (entry points, angles, lengths), select 'Yes' to enter edit mode."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "In the 3D view, manually adjust the position and orientation of each screw trajectory as needed.",
      "detailed": "Modify the screw paths by dragging control points in the 3D view to optimize entry points, direction, and depth. Ensure screws are safely positioned within bone corridors and avoid critical structures. Make your adjustments, then click Done when satisfied."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Final Screws",
      "simple": "Click the 'Regenerate screws from edited lines' button to finalize the modified trajectories.",
      "detailed": "After manual adjustments, regenerate the screw models to reflect your edits. This produces the definitive screw placement data for surgical reference. Click 'Regenerate screws from edited lines' to confirm the changes."
    },
    {
      "step_id": "cb_step_15",
      "title": "Exit Screw Editing Mode",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to exit the editing mode.",
      "detailed": "Once you are satisfied with the screw trajectories, disengage edit mode by unchecking the box. This finalizes the planning and returns to the main interface. Untick the checkbox to complete the process."
    }
  ]
}
